import React, { useState, useEffect, useMemo, useRef } from "react";
import menkesLogo from "../../images/menkeslogo.webp";
import solmarLogo from "../../images/solmarlogo.webp";
import tributeLogo from "../../images/tributelogo.png";

const metrics = [
  {
    k: "10+",
    label: "Years on enterprise sites",
    body: "Hands-on experience as a Site Superintendent on high-rise residential and mixed-use developments.",
  },
  {
    k: "$50M+",
    label: "Cumulative project budgets",
    body: "Direct oversight of multi-million dollar scopes from foundation through deficiency closeout.",
  },
  {
    k: "On-Time",
    label: "Timeline & logistics",
    body: "Critical-path scheduling, trade coordination, and city inspection handling honed at scale.",
  },
];

const AnimatedCounter = ({ text }) => {
  const [count, setCount] = useState(0);
  const [hasStarted, setHasStarted] = useState(false);
  const counterRef = useRef(null);
  const match = useMemo(() => text.match(/^(\D*)(\d+)(\D*)$/), [text]);

  useEffect(() => {
    if (!match) return;
    let hasTriggered = false;
    const target = parseInt(match[2], 10);
    const duration = 2000;

    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting && !hasTriggered) {
          hasTriggered = true;
          setHasStarted(true);
          let startTimestamp = null;
          const step = (timestamp) => {
            if (!startTimestamp) startTimestamp = timestamp;
            const progress = Math.min((timestamp - startTimestamp) / duration, 1);
            const easeOut = progress === 1 ? 1 : 1 - Math.pow(2, -10 * progress);
            setCount(Math.floor(easeOut * target));
            if (progress < 1) window.requestAnimationFrame(step);
          };
          window.requestAnimationFrame(step);
          if (counterRef.current) observer.disconnect();
        }
      },
      { threshold: 0.1 }
    );

    if (counterRef.current) observer.observe(counterRef.current);
    return () => observer.disconnect();
  }, [match]);

  if (!match) return <span>{text}</span>;

  return (
    <span ref={counterRef}>
      {match[1]}{hasStarted ? count : 0}{match[3]}
    </span>
  );
};

export default function Experience() {
  return (
    <section
      id="experience"
      data-testid="experience-section"
      className="py-28 md:py-40"
      style={{ backgroundColor: "#EDEAE5" }}
    >
      <div className="max-w-7xl mx-auto px-6 md:px-10">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 lg:gap-20">

          <div className="lg:col-span-5 reveal">
            <div className="flex items-center gap-3 mb-6">
              <span className="block w-10 h-px bg-brand-accent" />
              <span
                className="text-xs tracking-[0.28em] uppercase font-medium"
                style={{ color: "#8A7D6B" }}
              >
                Our Roots
              </span>
            </div>
            <h2
              data-testid="experience-headline"
              className="font-display text-4xl md:text-5xl lg:text-6xl font-medium tracking-tighter leading-[1.05]"
              style={{ color: "#1A1A1A" }}
            >
              An enterprise pedigree,{" "}
              <span style={{ color: "#A09080" }}>brought home.</span>
            </h2>
            <p
              className="mt-8 text-lg leading-relaxed max-w-md"
              style={{ color: "#5A5048" }}
            >
              Sunwest Builds was founded on a decade of work for Canada&apos;s most rigorous developers.
              That same discipline now lives inside every residential project we touch.
            </p>

            {/* Logo trust bar */}
            <div className="mt-12 md:mt-16" data-testid="experience-developers">
              <div
                className="text-xs tracking-[0.28em] uppercase font-medium mb-6"
                style={{ color: "#A09080" }}
              >
                Background with
              </div>
              <div className="flex flex-nowrap items-center justify-between gap-4 md:gap-6 w-full pr-4">
                <img
                  src={menkesLogo}
                  alt="Menkes Developments"
                  className="h-6 md:h-8 w-auto max-w-[30%] object-contain grayscale opacity-40 hover:grayscale-0 hover:opacity-100 transition-all duration-500 shrink"
                />
                <img
                  src={solmarLogo}
                  alt="Solmar Developments"
                  className="h-10 md:h-14 w-auto max-w-[30%] object-contain grayscale opacity-40 hover:grayscale-0 hover:opacity-100 transition-all duration-500 shrink"
                />
                <img
                  src={tributeLogo}
                  alt="Tribute Communities"
                  className="h-6 md:h-8 w-auto max-w-[30%] object-contain grayscale opacity-40 hover:grayscale-0 hover:opacity-100 transition-all duration-500 shrink"
                />
              </div>
            </div>
          </div>

          {/* Metric cards — white cards pop off the darker stone bg */}
          <div className="lg:col-span-7 grid grid-cols-1 sm:grid-cols-3 gap-px" style={{ backgroundColor: "#D8D4CE" }}>
            {metrics.map((m, i) => (
              <div
                key={m.label}
                data-testid={`experience-metric-${i}`}
                className="reveal p-8 md:p-10 flex flex-col justify-between min-h-[260px]"
                style={{ backgroundColor: "#F5F2EE" }}
              >
                <div>
                  <span
                    className="font-display text-5xl md:text-6xl font-medium tracking-tighter"
                    style={{ color: "#1A1A1A" }}
                  >
                    <AnimatedCounter text={m.k} />
                  </span>
                  <div
                    className="mt-3 text-sm uppercase tracking-widest"
                    style={{ color: "#A09080" }}
                  >
                    {m.label}
                  </div>
                </div>
                <p className="mt-8 text-sm leading-relaxed" style={{ color: "#5A5048" }}>
                  {m.body}
                </p>
              </div>
            ))}
          </div>

        </div>
      </div>
    </section>
  );
}
